        if (stackY.left === null) stackY.left = target.y - size.height / 2;
        y = stackY.left;
        stackY.left = y + size.height + NOTE_STACK_GAP;
        attachX = x + size.width;                // right edge of note
        attachY = y + size.height / 2;
