        y = cursors.top - size.height;
        if (stackX.top === null) stackX.top = target.x - size.width / 2;
        x = stackX.top;
        stackX.top = x + size.width + NOTE_STACK_GAP;
        attachX = x + size.width / 2;
        attachY = y + size.height;               // bottom edge of note
