      svg.push('<rect x="' + outsideBox.x + '" y="' + outsideBox.y +
        '" width="' + outsideBox.w + '" height="' + outsideBox.h +
        '" rx="6" fill="#f5f5f0" stroke="#8a8a82" stroke-width="1" stroke-dasharray="4,3"/>');
